void test_CB_BE_0000()
{
    if (skip_test_CB_BE_0000)
    {
        TEST_SKIP("Skipping");
        return;
    }
    mmap.Reset();
    auto mmapResult = mmap.Initialize(MinRomBankCount, MinVramBankCount, 1, MinWramBankCount);
    TEST_ASSERT_(mmapResult.IsSuccess(), "%s", mmapResult.GetStatusDescription());

    // Initial state

    WriteRegisterWord(RegisterType::PC, 0x8E1B);
    WriteRegisterWord(RegisterType::SP, 0xB6D1);
    WriteRegisterByte(RegisterType::A, 0x75);
    WriteRegisterByte(RegisterType::B, 0x29);
    WriteRegisterByte(RegisterType::C, 0x6E);
    WriteRegisterByte(RegisterType::D, 0x59);
    WriteRegisterByte(RegisterType::E, 0x34);
    WriteRegisterFlag(0xA0);
    WriteRegisterByte(RegisterType::H, 0x35);
    WriteRegisterByte(RegisterType::L, 0x9D);
    mmap.DisableIME();
    WriteRegisterByte(RegisterType::IE, 0x01);
    WriteMemory(0x8E1C, 0xBE);
    WriteMemory(0x8E1B, 0xCB);
    WriteMemory(0x359D, 0x6C);

    // Execute step
    {
        auto resultByte = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte.IsSuccess(), "%s", resultByte.GetStatusDescription());
        auto ticks = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte), mmap);
        TEST_ASSERT(ticks == GetInstructionTicks(static_cast<const Byte&>(resultByte), 0x00));

        // Execute additional step for prefix
        auto resultByte2 = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte2.IsSuccess(), "%s", resultByte2.GetStatusDescription());
        auto ticks2 = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte2), mmap);
        TEST_ASSERT(ticks2 == GetInstructionTicks(static_cast<const Byte&>(resultByte2), 0xCB));
        TEST_ASSERT(ticks + ticks2 == 16);
    }

    // Final state
            
    CheckRegisterByte(RegisterType::A, 0x75);
    CheckRegisterByte(RegisterType::B, 0x29);
    CheckRegisterByte(RegisterType::C, 0x6E);
    CheckRegisterByte(RegisterType::D, 0x59);
    CheckRegisterByte(RegisterType::E, 0x34);
    CheckRegisterFlag(0xA0);
    CheckRegisterByte(RegisterType::H, 0x35);
    CheckRegisterByte(RegisterType::L, 0x9D);
    CheckRegisterWord(RegisterType::PC, 0x8E1D);
    CheckRegisterWord(RegisterType::SP, 0xB6D1);
    TEST_ASSERT(!mmap.IMEEnabled());
    CheckMemory(0x359D, 0x6C);
    CheckMemory(0x8E1B, 0xCB);
    CheckMemory(0x8E1C, 0xBE);
}

